  2993 |   // X+C2 >u C -> X+(C2-C-1) <u ~C
  2994 |   if (Pred == ICmpInst::ICMP_UGT)
  2995 |     return new ICmpInst(ICmpInst::ICMP_ULT,
  2996 |                         Builder.CreateAdd(X, ConstantInt::get(Ty, *C2 - C - 1)),
  2997 |                         ConstantInt::get(Ty, ~C));
  2998 | 
  2999 |   return nullptr;
  3000 | }
